"use client";

import { motion, AnimatePresence } from "framer-motion";
import { Plus, Edit2, Trash2, Search, X, Save, Loader2, Globe, Tag, Image as ImageIcon } from "lucide-react";
import Image from "next/image";
import { useState, useEffect } from "react";

export default function AdminCategories() {
    const [categories, setCategories] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState("");
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingCategory, setEditingCategory] = useState<any>(null);
    const [formData, setFormData] = useState({
        name: "",
        slug: "",
        description: "",
        image: "",
        metaTitle: "",
        metaDescription: ""
    });

    const fetchCategories = async () => {
        setLoading(true);
        try {
            const res = await fetch('/api/categories');
            const data = await res.json();
            setCategories(data);
        } catch (error) {
            console.error("Failed to fetch categories:", error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchCategories();
    }, []);

    const handleOpenModal = (category: any = null) => {
        if (category) {
            setEditingCategory(category);
            setFormData({
                name: category.name,
                slug: category.slug,
                description: category.description,
                image: category.image,
                metaTitle: category.metaTitle || "",
                metaDescription: category.metaDescription || ""
            });
        } else {
            setEditingCategory(null);
            setFormData({
                name: "",
                slug: "",
                description: "",
                image: "",
                metaTitle: "",
                metaDescription: ""
            });
        }
        setIsModalOpen(true);
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        const method = editingCategory ? 'PUT' : 'POST';
        const url = editingCategory ? `/api/categories/${editingCategory.id}` : '/api/categories';

        try {
            const res = await fetch(url, {
                method,
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(formData),
            });
            if (res.ok) {
                setIsModalOpen(false);
                fetchCategories();
            }
        } catch (error) {
            console.error("Failed to save category:", error);
        }
    };

    const handleDelete = async (id: string) => {
        if (!confirm("Are you sure? This will not delete products in this category, but they will become uncategorized.")) return;
        try {
            const res = await fetch(`/api/categories/${id}`, { method: 'DELETE' });
            if (res.ok) {
                setCategories(prev => prev.filter(c => c.id !== id));
            }
        } catch (error) {
            console.error("Failed to delete category:", error);
        }
    };

    const filteredCategories = categories.filter(c =>
        c.name.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="max-w-7xl mx-auto space-y-8 font-outfit">
            {/* Header */}
            <div className="flex flex-col sm:flex-row gap-4 items-start sm:items-center justify-between">
                <div>
                    <h1 className="text-4xl font-black tracking-tight text-surface-950 mb-2 uppercase">
                        PART <span className="text-brand-600">CATEGORIES</span>
                    </h1>
                    <p className="text-surface-500 font-medium">Organize your inventory and optimize for search engines.</p>
                </div>

                <button
                    onClick={() => handleOpenModal()}
                    className="flex items-center gap-2 px-8 py-4 bg-brand-600 hover:bg-brand-700 text-white font-black rounded-2xl transition-all shadow-xl shadow-brand-600/20 active:scale-95 uppercase tracking-widest text-sm"
                >
                    <Plus size={20} />
                    <span>CREATE CATEGORY</span>
                </button>
            </div>

            {/* Toolbar */}
            <div className="bg-white p-6 rounded-[2.5rem] border border-surface-200 shadow-sm">
                <div className="relative w-full sm:w-96">
                    <Search size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-surface-400" />
                    <input
                        type="text"
                        placeholder="Search categories..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full bg-surface-50 border border-surface-200 rounded-2xl py-3 pl-12 pr-6 text-surface-900 focus:outline-none focus:border-brand-500 transition-all font-bold placeholder:text-surface-300"
                    />
                </div>
            </div>

            {/* Table */}
            <div className="bg-white rounded-[2.5rem] border border-surface-200 shadow-sm overflow-hidden">
                <div className="overflow-x-auto">
                    {loading ? (
                        <div className="flex items-center justify-center py-24">
                            <Loader2 className="w-10 h-10 text-brand-600 animate-spin" />
                        </div>
                    ) : (
                        <table className="w-full text-left border-collapse">
                            <thead>
                                <tr className="bg-surface-50/50 border-b border-surface-200 text-surface-500 font-black text-[10px] uppercase tracking-[0.2em]">
                                    <th className="py-6 px-8">Category / Visual</th>
                                    <th className="py-6 px-8">Slug</th>
                                    <th className="py-6 px-8">Product Count</th>
                                    <th className="py-6 px-8 text-right">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-surface-100">
                                {filteredCategories.map((category, i) => (
                                    <motion.tr
                                        key={category.id}
                                        initial={{ opacity: 0, y: 10 }}
                                        animate={{ opacity: 1, y: 0 }}
                                        transition={{ delay: i * 0.05 }}
                                        className="hover:bg-surface-50/50 transition-colors group"
                                    >
                                        <td className="py-5 px-8">
                                            <div className="flex items-center gap-4">
                                                <div className="relative w-14 h-14 rounded-2xl overflow-hidden border border-surface-200 bg-surface-50">
                                                    <Image src={category.image} alt={category.name} fill className="object-cover group-hover:scale-110 transition-transform duration-500" />
                                                </div>
                                                <div className="font-black text-surface-950 group-hover:text-brand-600 transition-colors uppercase tracking-tight">{category.name}</div>
                                            </div>
                                        </td>
                                        <td className="py-5 px-8 text-sm font-bold text-surface-400 font-mono">
                                            /{category.slug}
                                        </td>
                                        <td className="py-5 px-8">
                                            <span className="font-black text-brand-600 bg-brand-50 px-4 py-1 rounded-full text-xs border border-brand-100 italic">
                                                {category._count?.products || 0} UNITS
                                            </span>
                                        </td>
                                        <td className="py-5 px-8">
                                            <div className="flex justify-end gap-2">
                                                <button
                                                    onClick={() => handleOpenModal(category)}
                                                    className="p-2.5 text-surface-400 hover:text-brand-600 hover:bg-brand-50 rounded-xl transition-all border border-transparent hover:border-brand-100 shadow-sm"
                                                >
                                                    <Edit2 size={18} />
                                                </button>
                                                <button
                                                    onClick={() => handleDelete(category.id)}
                                                    className="p-2.5 text-surface-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all border border-transparent hover:border-red-100 shadow-sm"
                                                >
                                                    <Trash2 size={18} />
                                                </button>
                                            </div>
                                        </td>
                                    </motion.tr>
                                ))}
                            </tbody>
                        </table>
                    )}
                </div>
            </div>

            {/* Modal */}
            <AnimatePresence>
                {isModalOpen && (
                    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            onClick={() => setIsModalOpen(false)}
                            className="absolute inset-0 bg-surface-950/40 backdrop-blur-md"
                        />
                        <motion.div
                            initial={{ opacity: 0, scale: 0.9, y: 20 }}
                            animate={{ opacity: 1, scale: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.9, y: 20 }}
                            className="relative w-full max-w-4xl bg-white rounded-[3rem] shadow-2xl overflow-hidden border border-surface-200"
                        >
                            <div className="flex items-center justify-between p-8 border-b border-surface-100">
                                <h2 className="text-2xl font-black text-surface-950 uppercase tracking-tight">
                                    {editingCategory ? 'Edit' : 'Create'} <span className="text-brand-600">Category</span>
                                </h2>
                                <button onClick={() => setIsModalOpen(false)} className="p-2 hover:bg-surface-100 rounded-xl transition-colors text-surface-400 hover:text-surface-900">
                                    <X size={24} />
                                </button>
                            </div>

                            <form onSubmit={handleSave} className="p-8 max-h-[70vh] overflow-y-auto custom-scrollbar">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                    {/* Core Info */}
                                    <div className="space-y-6">
                                        <div className="space-y-2">
                                            <label className="text-[10px] font-black text-surface-500 uppercase tracking-widest pl-1">Category Name</label>
                                            <div className="relative">
                                                <Tag className="absolute left-4 top-1/2 -translate-y-1/2 text-surface-300" size={18} />
                                                <input
                                                    required
                                                    value={formData.name}
                                                    onChange={e => {
                                                        const name = e.target.value;
                                                        const slug = name.toLowerCase().replace(/[^a-z0-9]/g, '-');
                                                        setFormData({ ...formData, name, slug });
                                                    }}
                                                    className="w-full bg-surface-50 border border-surface-200 rounded-2xl py-3 pl-12 pr-6 font-bold text-surface-900 focus:border-brand-500 outline-none"
                                                    placeholder="e.g. Braking Systems"
                                                />
                                            </div>
                                        </div>

                                        <div className="space-y-2">
                                            <label className="text-[10px] font-black text-surface-500 uppercase tracking-widest pl-1">Slug (URL)</label>
                                            <input
                                                required
                                                value={formData.slug}
                                                onChange={e => setFormData({ ...formData, slug: e.target.value })}
                                                className="w-full bg-surface-50 border border-surface-200 rounded-2xl py-3 px-6 font-bold text-surface-400 font-mono focus:border-brand-500 outline-none"
                                            />
                                        </div>

                                        <div className="space-y-2">
                                            <label className="text-[10px] font-black text-surface-500 uppercase tracking-widest pl-1">Cover Image URL</label>
                                            <div className="relative">
                                                <ImageIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-surface-300" size={18} />
                                                <input
                                                    required
                                                    value={formData.image}
                                                    onChange={e => setFormData({ ...formData, image: e.target.value })}
                                                    className="w-full bg-surface-50 border border-surface-200 rounded-2xl py-3 pl-12 pr-6 font-bold text-surface-900 focus:border-brand-500 outline-none"
                                                    placeholder="https://..."
                                                />
                                            </div>
                                        </div>
                                    </div>

                                    {/* SEO & Description */}
                                    <div className="space-y-6">
                                        <div className="space-y-2">
                                            <label className="text-[10px] font-black text-surface-500 uppercase tracking-widest pl-1">SEO Meta Title</label>
                                            <div className="relative">
                                                <Globe className="absolute left-4 top-1/2 -translate-y-1/2 text-surface-300" size={18} />
                                                <input
                                                    value={formData.metaTitle}
                                                    onChange={e => setFormData({ ...formData, metaTitle: e.target.value })}
                                                    className="w-full bg-surface-50 border border-surface-200 rounded-2xl py-3 pl-12 pr-6 font-bold text-surface-900 focus:border-brand-500 outline-none"
                                                    placeholder="SEO optimized title..."
                                                />
                                            </div>
                                        </div>

                                        <div className="space-y-2">
                                            <label className="text-[10px] font-black text-surface-500 uppercase tracking-widest pl-1">SEO Meta Description</label>
                                            <textarea
                                                rows={2}
                                                value={formData.metaDescription}
                                                onChange={e => setFormData({ ...formData, metaDescription: e.target.value })}
                                                className="w-full bg-surface-50 border border-surface-200 rounded-2xl py-3 px-4 font-bold text-surface-900 focus:border-brand-500 outline-none resize-none"
                                                placeholder="Brief description for search engines..."
                                            />
                                        </div>

                                        <div className="space-y-2">
                                            <label className="text-[10px] font-black text-surface-500 uppercase tracking-widest pl-1">Description</label>
                                            <textarea
                                                required
                                                rows={4}
                                                value={formData.description}
                                                onChange={e => setFormData({ ...formData, description: e.target.value })}
                                                className="w-full bg-surface-50 border border-surface-200 rounded-2xl py-3 px-4 font-bold text-surface-900 focus:border-brand-500 outline-none resize-none"
                                                placeholder="Briefly describe this category..."
                                            />
                                        </div>
                                    </div>
                                </div>

                                <div className="mt-12 flex justify-end gap-4">
                                    <button
                                        type="button"
                                        onClick={() => setIsModalOpen(false)}
                                        className="px-8 py-4 bg-surface-50 hover:bg-surface-100 text-surface-600 font-black rounded-2xl transition-all uppercase tracking-widest text-sm"
                                    >
                                        Discard
                                    </button>
                                    <button
                                        type="submit"
                                        className="flex items-center gap-2 px-12 py-4 bg-brand-600 hover:bg-brand-700 text-white font-black rounded-2xl transition-all shadow-xl shadow-brand-600/20 active:scale-95 uppercase tracking-widest text-sm"
                                    >
                                        <Save size={20} />
                                        <span>SAVE CATEGORY</span>
                                    </button>
                                </div>
                            </form>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>
        </div>
    );
}

"use client";

import { motion } from "framer-motion";
import { Lock, Mail, ArrowRight, Hexagon, ShieldAlert } from "lucide-react";
import { useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { signIn } from "next-auth/react";
import { toast } from "sonner";

export default function AdminLogin() {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const router = useRouter();
    const [loading, setLoading] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);

        const result = await signIn("credentials", {
            email,
            password,
            redirect: false,
        });

        if (result?.error) {
            toast.error("Access Denied", {
                description: "The credentials provided do not have administrative clearance."
            });
            setLoading(false);
        } else {
            toast.success("Security Clearance Verified");
            router.push("/admin/dashboard");
        }
    };

    return (
        <div className="min-h-screen bg-surface-50 flex items-center justify-center p-4 font-outfit">
            <div className="w-full max-w-md">
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="bg-white rounded-[2.5rem] p-10 border border-surface-200 shadow-xl shadow-brand-600/5 relative overflow-hidden"
                >
                    {/* Brand Header */}
                    <div className="flex flex-col items-center mb-10">
                        <motion.div
                            animate={{ rotate: 360 }}
                            transition={{ duration: 20, repeat: Infinity, ease: "linear" }}
                            className="w-16 h-16 bg-brand-50 rounded-2xl flex items-center justify-center text-brand-600 mb-6"
                        >
                            <Hexagon size={32} />
                        </motion.div>
                        <h1 className="text-3xl font-black text-surface-950 uppercase tracking-tight">Admin <span className="text-brand-600">Terminal</span></h1>
                        <p className="text-surface-500 font-bold text-xs tracking-widest uppercase mt-2">Authorization Required</p>
                    </div>


                    <form onSubmit={handleSubmit} className="space-y-6">
                        <div className="space-y-2">
                            <label className="text-xs font-black text-surface-500 uppercase tracking-widest ml-1">Secure Email</label>
                            <div className="relative">
                                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-surface-400" size={20} />
                                <input
                                    type="email"
                                    required
                                    value={email}
                                    onChange={(e) => setEmail(e.target.value)}
                                    className="w-full bg-surface-50 border border-surface-200 rounded-2xl pl-12 pr-4 py-4 focus:outline-none focus:border-brand-500 focus:ring-4 focus:ring-brand-500/5 transition-all font-bold placeholder:text-surface-300"
                                    placeholder="admin@apexauto.com"
                                />
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-xs font-black text-surface-500 uppercase tracking-widest ml-1">Access Key</label>
                            <div className="relative">
                                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-surface-400" size={20} />
                                <input
                                    type="password"
                                    required
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    className="w-full bg-surface-50 border border-surface-200 rounded-2xl pl-12 pr-4 py-4 focus:outline-none focus:border-brand-500 focus:ring-4 focus:ring-brand-500/5 transition-all font-bold placeholder:text-surface-300"
                                    placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                                />
                            </div>
                        </div>

                        <button
                            disabled={loading}
                            className="w-full py-5 bg-brand-600 hover:bg-brand-700 disabled:bg-surface-300 text-white font-black rounded-2xl transition-all active:scale-[0.98] shadow-lg shadow-brand-600/20 uppercase tracking-widest flex items-center justify-center gap-3 group"
                        >
                            {loading ? (
                                "Initializing..."
                            ) : (
                                <>
                                    Log In <ArrowRight size={20} className="group-hover:translate-x-1 transition-transform" />
                                </>
                            )}
                        </button>
                    </form>

                    <div className="mt-8 pt-8 border-t border-surface-100 flex justify-center">
                        <Link href="/" className="text-sm font-bold text-surface-400 hover:text-brand-600 transition-colors uppercase tracking-widest">
                            Return to Frontend
                        </Link>
                    </div>
                </motion.div>

                <p className="text-center mt-8 text-surface-400 text-xs font-bold uppercase tracking-[0.2em]">
                    Apex Auto Secure Management Protocol v4.0.1
                </p>
            </div>
        </div>
    );
}

"use client";

import { motion } from "framer-motion";
import { Search, Eye, MoreHorizontal, CheckCircle2, Clock, XCircle, Truck, AlertCircle, Loader2 } from "lucide-react";
import { useState, useEffect } from "react";

// Mock Data
const initialOrders = [
    { id: "ORD-8925", customer: "Alex Mercer", email: "a.mercer@citadel.net", date: "2026-03-08", total: 1799.98, status: "Completed", items: 2 },
    { id: "ORD-8924", customer: "Sarah Kerrigan", email: "ghost@dominion.gov", date: "2026-03-07", total: 4999.99, status: "Processing", items: 1 },
    { id: "ORD-8923", customer: "David Bowman", email: "dbowman@discovery.space", date: "2026-03-07", total: 899.99, status: "Shipped", items: 1 },
    { id: "ORD-8922", customer: "Motoko Kusanagi", email: "major@section9.jp", date: "2026-03-06", total: 249.99, status: "Cancelled", items: 1 },
    { id: "ORD-8921", customer: "Neo", email: "neo@zion.matrix", date: "2026-03-05", total: 1299.99, status: "Completed", items: 1 },
];

export default function AdminOrders() {
    const [orders, setOrders] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState("");

    const fetchOrders = async () => {
        try {
            const res = await fetch('/api/orders');
            const data = await res.json();
            setOrders(data);
        } catch (error) {
            console.error("Failed to fetch orders:", error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchOrders();
    }, []);

    const handleStatusUpdate = async (orderId: string, newStatus: string) => {
        try {
            const res = await fetch(`/api/orders/${orderId}`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ status: newStatus }),
            });
            if (res.ok) {
                // Optimistic update
                setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: newStatus } : o));
            }
        } catch (error) {
            console.error("Failed to update status:", error);
        }
    };

    const getStatusIcon = (status: string) => {
        switch (status) {
            case 'COMPLETED':
            case 'Completed': return <CheckCircle2 size={14} />;
            case 'PROCESSING':
            case 'Processing': return <Clock size={14} />;
            case 'SHIPPED':
            case 'Shipped': return <Truck size={14} />;
            case 'CANCELLED':
            case 'Cancelled': return <XCircle size={14} />;
            default: return <AlertCircle size={14} />;
        }
    };

    const getStatusStyle = (status: string) => {
        switch (status.toUpperCase()) {
            case 'COMPLETED': return 'bg-emerald-50 text-emerald-600 border-emerald-100';
            case 'PROCESSING': return 'bg-amber-50 text-amber-600 border-amber-100';
            case 'SHIPPED': return 'bg-blue-50 text-blue-600 border-blue-100';
            case 'CANCELLED': return 'bg-red-50 text-red-600 border-red-100';
            default: return 'bg-surface-50 text-surface-500 border-surface-100';
        }
    };

    return (
        <div className="max-w-7xl mx-auto space-y-8 font-outfit">
            {/* Header */}
            <div className="flex flex-col sm:flex-row gap-4 items-start sm:items-center justify-between">
                <div>
                    <h1 className="text-4xl font-black tracking-tight text-surface-950 uppercase">
                        SALES <span className="text-brand-600">LEDGER</span>
                    </h1>
                    <p className="text-surface-500 font-medium">Monitor system transactions and order fulfillment status.</p>
                </div>
            </div>

            {/* Toolbar */}
            <div className="bg-white p-6 rounded-[2.5rem] border border-surface-200 shadow-sm flex flex-col sm:flex-row gap-4 items-center justify-between">
                <div className="relative w-full sm:w-96">
                    <Search size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-surface-400" />
                    <input
                        type="text"
                        placeholder="Search IDs, customers, or emails..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full bg-surface-50 border border-surface-200 rounded-2xl py-3 pl-12 pr-6 text-surface-900 focus:outline-none focus:border-brand-500 transition-all font-bold placeholder:text-surface-300"
                    />
                </div>

                <div className="flex gap-3">
                    <select className="bg-surface-50 border border-surface-200 rounded-2xl py-3 px-6 text-surface-600 font-bold focus:outline-none hover:border-surface-400 cursor-pointer transition-colors">
                        <option value="all">Every Status</option>
                        <option value="completed">Completed</option>
                        <option value="processing">Processing</option>
                        <option value="shipped">Shipped</option>
                    </select>
                </div>
            </div>

            {/* Table */}
            <div className="bg-white rounded-[2.5rem] border border-surface-200 shadow-sm overflow-hidden">
                <div className="overflow-x-auto">
                    {loading ? (
                        <div className="flex items-center justify-center py-24">
                            <Loader2 className="w-10 h-10 text-brand-600 animate-spin" />
                        </div>
                    ) : orders.length === 0 ? (
                        <div className="text-center py-24">
                            <p className="text-surface-400 font-black uppercase tracking-widest text-lg">No transactions found.</p>
                        </div>
                    ) : (
                        <table className="w-full text-left border-collapse">
                            <thead>
                                <tr className="bg-surface-50/50 border-b border-surface-200 text-surface-500 font-black text-[10px] uppercase tracking-[0.2em]">
                                    <th className="py-6 px-8">Transaction ID</th>
                                    <th className="py-6 px-8">Customer Data</th>
                                    <th className="py-6 px-8">Date Initiated</th>
                                    <th className="py-6 px-8">Total Revenue</th>
                                    <th className="py-6 px-8">Status / Workflow</th>
                                    <th className="py-6 px-8 text-right">Inspect</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-surface-100">
                                {orders.map((order, i) => (
                                    <motion.tr
                                        key={order.id}
                                        initial={{ opacity: 0, x: -10 }}
                                        animate={{ opacity: 1, x: 0 }}
                                        transition={{ delay: i * 0.05 }}
                                        className="hover:bg-surface-50/50 transition-colors group"
                                    >
                                        <td className="py-5 px-8">
                                            <span className="font-black text-surface-950 group-hover:text-brand-600 transition-colors">
                                                {order.id.substring(0, 8).toUpperCase()}
                                            </span>
                                        </td>
                                        <td className="py-5 px-8">
                                            <div className="font-bold text-surface-950 text-sm">{order.shippingName}</div>
                                            <div className="text-[10px] font-bold text-surface-400 uppercase tracking-widest">{order.user?.email || 'Guest User'}</div>
                                        </td>
                                        <td className="py-5 px-8">
                                            <span className="text-sm font-bold text-surface-500 uppercase tracking-tighter">
                                                {new Date(order.createdAt).toLocaleDateString()}
                                            </span>
                                        </td>
                                        <td className="py-5 px-8">
                                            <span className="font-black text-surface-950">${parseFloat(order.total).toFixed(2)}</span>
                                        </td>
                                        <td className="py-5 px-8">
                                            <div className="flex flex-col gap-1.5 items-start">
                                                <select
                                                    value={order.status.toUpperCase()}
                                                    onChange={(e) => handleStatusUpdate(order.id, e.target.value)}
                                                    className={`inline-flex items-center gap-2 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border cursor-pointer outline-none transition-all ${getStatusStyle(order.status)}`}
                                                >
                                                    <option value="PENDING">Pending</option>
                                                    <option value="PROCESSING">Processing</option>
                                                    <option value="SHIPPED">Shipped</option>
                                                    <option value="DELIVERED">Delivered</option>
                                                    <option value="CANCELLED">Cancelled</option>
                                                </select>
                                                <span className="text-[10px] font-black text-surface-400 uppercase tracking-widest ml-1">{order.orderItems?.length || 0} UNIT(S)</span>
                                            </div>
                                        </td>
                                        <td className="py-5 px-8">
                                            <div className="flex justify-end gap-2">
                                                <button className="p-2.5 text-surface-400 hover:text-brand-600 hover:bg-brand-50 rounded-xl transition-all border border-transparent hover:border-brand-100 shadow-sm">
                                                    <Eye size={18} />
                                                </button>
                                                <button className="p-2.5 text-surface-400 hover:text-surface-900 hover:bg-surface-50 rounded-xl transition-all border border-transparent hover:border-surface-200">
                                                    <MoreHorizontal size={18} />
                                                </button>
                                            </div>
                                        </td>
                                    </motion.tr>
                                ))}
                            </tbody>
                        </table>
                    )}
                </div>
            </div>
        </div>
    );
}

