import bcrypt from 'bcryptjs';
import jwt from 'jsonwebtoken';

const JWT_SECRET = process.env.JWT_SECRET || 'apex_auto_default_secret';

export async function hashPassword(password: string) {
    return await bcrypt.hash(password, 12);
}

export async function comparePassword(password: string, hashed: string) {
    return await bcrypt.compare(password, hashed);
}

export function signToken(payload: any) {
    return jwt.sign(payload, JWT_SECRET, { expiresIn: '7d' });
}

export function verifyToken(token: string) {
    try {
        return jwt.verify(token, JWT_SECRET);
    } catch (error) {
        return null;
    }
}

import { auth } from "@/auth"

export default auth((req) => {
  const isLoggedIn = !!req.auth
  const { nextUrl } = req

  const isApiAuthRoute = nextUrl.pathname.startsWith("/api/auth")
  const isPublicRoute = ["/", "/products", "/categories", "/about"].includes(nextUrl.pathname) || nextUrl.pathname.startsWith("/products/")
  const isAuthRoute = nextUrl.pathname.startsWith("/auth")
  const isAdminRoute = nextUrl.pathname.startsWith("/admin")

  if (isApiAuthRoute) return undefined

  if (isAuthRoute) {
    if (isLoggedIn) {
      return Response.redirect(new URL("/", nextUrl))
    }
    return undefined
  }

  if (isAdminRoute) {
    if (!isLoggedIn) {
      return Response.redirect(new URL("/auth/login", nextUrl))
    }
    const role = (req.auth?.user as any)?.role
    if (role !== "ADMIN") {
      return Response.redirect(new URL("/", nextUrl))
    }
    return undefined
  }

  if (!isLoggedIn && !isPublicRoute) {
    return Response.redirect(new URL("/auth/login", nextUrl))
  }

  return undefined
})

export const config = {
  matcher: ["/((?!.+\\.[\\w]+$|_next).*)", "/", "/(api|trpc)(.*)"],
}

import { create } from 'zustand';
import { persist } from 'zustand/middleware';

export type Currency = {
    code: string;
    symbol: string;
    rate: number; // rate relative to USD
};

interface SettingsState {
    storeName: string;
    currency: Currency;
    availableCurrencies: Currency[];
    setCurrency: (code: string) => void;
    updateRate: (code: string, newRate: number) => void;
    syncSettings: () => Promise<void>;
}

export const useSettingsStore = create<SettingsState>()(
    persist(
        (set, get) => ({
            storeName: 'Apex Auto Parts',
            currency: { code: 'USD', symbol: '$', rate: 1 },
            availableCurrencies: [
                { code: 'USD', symbol: '$', rate: 1 },
                { code: 'LKR', symbol: 'Rs.', rate: 300 },
                { code: 'EUR', symbol: 'Γé¼', rate: 0.92 },
                { code: 'GBP', symbol: '┬ú', rate: 0.79 },
            ],
            setCurrency: (code) => set((state) => {
                const newCurrency = state.availableCurrencies.find(c => c.code === code);
                return newCurrency ? { currency: newCurrency } : state;
            }),
            updateRate: (code, newRate) => set((state) => ({
                availableCurrencies: state.availableCurrencies.map(c =>
                    c.code === code ? { ...c, rate: newRate } : c
                ),
                currency: state.currency.code === code
                    ? { ...state.currency, rate: newRate }
                    : state.currency
            })),
            syncSettings: async () => {
                try {
                    const res = await fetch('/api/settings');
                    const data = await res.json();
                    if (data && !data.error) {
                        set({
                            storeName: data.storeName,
                            currency: {
                                code: data.currencyCode,
                                symbol: data.currencySymbol,
                                rate: 1 // For now, we assume the DB currency is the base
                            }
                        });
                    }
                } catch (error) {
                    console.error("Failed to sync settings:", error);
                }
            }
        }),
        {
            name: 'settings-storage',
        }
    )
);
